SELECT * FROM road_edge


        AND road_id = #{params.roadId}


        AND road_name LIKE CONCAT('%', #{params.roadName}, '%')


        AND road_type = #{params.roadType}

    and deleted_at IS NULL

ORDER BY created_at DESC
LIMIT #{pageSize} OFFSET #{offset}

